    q->maxsize= q->maxsize*2;
  }
  q->size++;
  q->ar[q->size] = elem;
  shiftUp(q, q->size);
}

void *fullPriGet(PriQueue *q) {
  void *result= q->ar[0];
  q->ar[0]= q->ar[q->size];
  q->size--;
  shiftDown(q, 0);
  return result;
}

