#include "pss.h"
#include "rwlock.h"

typedef struct waiter {
    pthread_cond_t cond;
    int ready;
} Waiter;

struct rwlock {
    pthread_mutex_t mutex;
    Queue *readers;
    Queue *writers;
    int active_readers;
    int active_writer;
};

static Waiter *makeWaiter(void) {
    Waiter *w = malloc(sizeof(Waiter));
    if (w == NULL) {
        perror("malloc");
        exit(1);
    }
    w->ready = 0;
    pthread_cond_init(&w->cond, NULL);
    return w;
}

static void destroyWaiter(Waiter *w) {
    pthread_cond_destroy(&w->cond);
    free(w);
}

static void drainQueue(Queue *q) {
    while (!emptyQueue(q)) {
        Waiter *w = get(q);
        destroyWaiter(w);
    }
}

RWLock *makeRWLock(void) {
    RWLock *rwl = malloc(sizeof(RWLock));
    if (rwl == NULL) {
        perror("malloc");
        exit(1);
    }
    pthread_mutex_init(&rwl->mutex, NULL);
    rwl->readers = makeQueue();
    rwl->writers = makeQueue();
    rwl->active_readers = 0;
    rwl->active_writer = 0;
    return rwl;
}

void destroyRWLock(RWLock *rwl) {
    if (rwl == NULL) {
        return;
    }
    pthread_mutex_lock(&rwl->mutex);
    drainQueue(rwl->readers);
    drainQueue(rwl->writers);
    pthread_mutex_unlock(&rwl->mutex);
    destroyQueue(rwl->readers);
    destroyQueue(rwl->writers);
    pthread_mutex_destroy(&rwl->mutex);
    free(rwl);
}

void enterRead(RWLock *rwl) {
    pthread_mutex_lock(&rwl->mutex);
    if (!rwl->active_writer && emptyQueue(rwl->writers)) {
        rwl->active_readers++;
        pthread_mutex_unlock(&rwl->mutex);
        return;
    }

    Waiter *w = makeWaiter();
    put(rwl->readers, w);
    while (!w->ready) {
        pthread_cond_wait(&w->cond, &rwl->mutex);
    }
    destroyWaiter(w);
    pthread_mutex_unlock(&rwl->mutex);
}

void exitRead(RWLock *rwl) {
    pthread_mutex_lock(&rwl->mutex);
    rwl->active_readers--;
    if (rwl->active_readers == 0 && !emptyQueue(rwl->writers)) {
        Waiter *w = get(rwl->writers);
        rwl->active_writer = 1;
        w->ready = 1;
        pthread_cond_signal(&w->cond);
    }
    pthread_mutex_unlock(&rwl->mutex);
}

void enterWrite(RWLock *rwl) {
    pthread_mutex_lock(&rwl->mutex);
    if (!rwl->active_writer && rwl->active_readers == 0) {
        rwl->active_writer = 1;
        pthread_mutex_unlock(&rwl->mutex);
        return;
    }

    Waiter *w = makeWaiter();
    put(rwl->writers, w);
    while (!w->ready) {
        pthread_cond_wait(&w->cond, &rwl->mutex);
    }
    destroyWaiter(w);
    pthread_mutex_unlock(&rwl->mutex);
}

void exitWrite(RWLock *rwl) {
    pthread_mutex_lock(&rwl->mutex);
    rwl->active_writer = 0;
    if (!emptyQueue(rwl->readers)) {
        while (!emptyQueue(rwl->readers)) {
            Waiter *w = get(rwl->readers);
            rwl->active_readers++;
            w->ready = 1;
            pthread_cond_signal(&w->cond);
        }
    }
    else if (!emptyQueue(rwl->writers)) {
        Waiter *w = get(rwl->writers);
        rwl->active_writer = 1;
        w->ready = 1;
        pthread_cond_signal(&w->cond);
    }
    pthread_mutex_unlock(&rwl->mutex);
}

