#!/usr/bin/env perl
use strict;
use warnings;
use Compress::Raw::Zlib qw(crc32);

my $out = pop @ARGV;
my @files = @ARGV;
open my $fh, '>:raw', $out or die "open $out: $!\n";

my @cd;
my $offset = 0;
for my $file (@files) {
    open my $in, '<:raw', $file or die "open $file: $!\n";
    local $/;
    my $data = <$in>;
    close $in;

    my $crc = crc32($data);
    my $name = $file;
    my $size = length($data);
    my $local = pack('VvvvvvVVVvv', 0x04034b50, 20, 0, 0, 0, 0, $crc, $size, $size, length($name), 0)
      . $name . $data;
    print {$fh} $local or die "write $out: $!\n";

    push @cd, pack('VvvvvvvVVVvvvvvVV',
                   0x02014b50, 20, 20, 0, 0, 0, 0,
                   $crc, $size, $size, length($name), 0, 0, 0, 0, 0, $offset)
      . $name;
    $offset += length($local);
}

my $cd_offset = $offset;
my $cd_data = join('', @cd);
print {$fh} $cd_data or die "write $out: $!\n";
my $cd_size = length($cd_data);
print {$fh} pack('VvvvvVVv', 0x06054b50, 0, 0, scalar(@files), scalar(@files), $cd_size, $cd_offset, 0)
  or die "write $out: $!\n";
close $fh or die "close $out: $!\n";
